1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	};
8	
9	const basePremium = (item: { type: string }): number =>
10	  BASE_PREMIUMS[item.type] ?? 0;
11	
12	export const processSteps = (customer: unknown, steps: Array<{ op: string; items: Array<{ type: string }> }>): unknown =>
13	  steps.map((step) => ({
14	    premium: step.items.reduce((sum, item) => sum + basePremium(item), 0) + PROCESSING_FEE,
15	  }));
